    status: PollStatus;
    /**
     * Opened At
     */
    opened_at: string | null;
    /**
     * Closes At
     */
    closes_at: string | null;
    /**
     * Closed At
     */
    closed_at: string | null;
    vote_visibility: ResourceVisibility;
    result_visibility: ResourceVisibility;
    /**
     * User Has Voted
     */
    user_has_voted: boolean;
    /**
     * User Can Vote
     */
    user_can_vote: boolean;
    /**
     * User Can See Results
     */
